/**
 * @summary Get recent challenge events for polling
 */
export const getGetRecentChallengeEventsUrl = (
  params?: GetRecentChallengeEventsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/challenge/events/recent?${stringifiedParams}`
    : `/api/challenge/events/recent`;
};

export const getRecentChallengeEvents = async (
  params?: GetRecentChallengeEventsParams,
  options?: RequestInit,
): Promise<ChallengeEvent[]> => {
  return customFetch<ChallengeEvent[]>(getGetRecentChallengeEventsUrl(params), {
    ...options,
    method: "GET",
  });
};

